import{_ as s,o as r,c as t,a2 as e}from"./chunks/framework.BS3ZfcoS.js";const g=JSON.parse('{"title":"零散视频","description":"","frontmatter":{"title":"零散视频","author":"","collection":"职场成长","series_order":22,"total_chars":9227},"headers":[],"relativePath":"career/misc-videos.md","filePath":"career/misc-videos.md"}'),o={name:"career/misc-videos.md"};function p(n,a,h,l,i,c){return r(),t("div",null,[...a[0]||(a[0]=[e('<div class="page-toc"><p class="page-toc-title">📑 本页目录</p><a href="#s-619" class="page-toc-link">零散视频</a>     <a href="#s-620" class="page-toc-link">职场新人如何让别人感觉你工作能力很强？看完直接有3年工作经验</a>     <a href="#s-622" class="page-toc-link">AI工作流保姆级教程｜小白友好 用好AI是普通人最大的杠杆</a>     <a href="#s-625" class="page-toc-link">如何把清晰的脑子养回来？看完你将不可逆地变聪明</a>     <a href="#s-630" class="page-toc-link">越是低能量，越要过有秩序的生活，好状态就是好运气</a>     <a href="#s-632" class="page-toc-link">上班累，下班瘫，如何快速恢复能量？千万别把身体当耗材</a>     <a href="#s-634" class="page-toc-link">为什么有些人看起来就工作能力很强？学会就能早点下班、摆脱瞎忙的职场微习惯</a>     <a href="#s-635" class="page-toc-link">不上班怎么活？未来5年你不得不应对的职场新变化</a>     <a href="#s-637" class="page-toc-link">向上社交如何落落大方不怯场？如何让贵人主动帮你?</a>     <a href="#s-640" class="page-toc-link">太急是一种很强的负能量 一个人如果长期处于过度压力中会慢慢变笨</a>     <a href="#s-642" class="page-toc-link">哪些诀窍真能让普通人挣到钱？年轻收入高的人都有迹可循</a>     <a href="#s-647" class="page-toc-link">越没钱越要对钱有概念，哪些诀窍真的能帮普通人搞到钱?</a>     <a href="#s-650" class="page-toc-link">普通人不缺努力，缺的是一个赚钱系统</a>     <a href="#s-653" class="page-toc-link">上班最可怕的事是让我居然开始期待退休，期待衰老</a>     <a href="#s-655" class="page-toc-link">冠军心态：人生没有失败，要么成长，要么成功</a>     <a href="#s-656" class="page-toc-link">我在杨幂身上看到了很值得学习的底气与自由</a>     <a href="#s-658" class="page-toc-link">普通人如何培养财运，照着做你就在变富的路上</a>     <a href="#s-659" class="page-toc-link">高敏感的人不适合待在太底层的环境，一定要想办法托举自己向上走</a>     <a href="#s-660" class="page-toc-link">30岁才明白，要尽早明确人生主线，不要浪费自己的算力</a>     <a href="#s-662" class="page-toc-link">ENFP挑战高效工作一天，最后是AI承担了所有</a>     <a href="#s-666" class="page-toc-link">原来身体出现这些症状，不是你懒，是初老了</a>     <a href="#s-667" class="page-toc-link">做强者其实比做弱者更轻松</a>     <a href="#s-668" class="page-toc-link">向全网200万名股东述职【姜Dora】一个百万粉博主的创业故事</a>     <a href="#s-669" class="page-toc-link">中国式亲情，我和我爸好像真的不熟。陪54岁北漂老爸工作的一天</a>     <a href="#s-671" class="page-toc-link">不要温和地脱下那件长衫</a>     <a href="#s-674" class="page-toc-link">考研成功vs失败的二本生，6年后怎么样了？</a>     <a href="#s-675" class="page-toc-link">20岁 vs 30岁开窍的6个变化</a>     <a href="#s-680" class="page-toc-link">十年情侣的居家日常，初恋变同事什么体验</a>     <a href="#s-682" class="page-toc-link">27岁，大厂裸辞不上班的一年</a>     <a href="#s-684" class="page-toc-link">5分钟帮你摆脱社恐 ｜ 2种社恐类型你是哪种</a></div><h2 id="s-619" tabindex="-1">零散视频 <a class="header-anchor" href="#s-619" aria-label="Permalink to &quot;零散视频 {#s-619}&quot;">​</a></h2><p>共29个视频</p><h3 id="s-620" tabindex="-1">职场新人如何让别人感觉你工作能力很强？看完直接有3年工作经验 <a class="header-anchor" href="#s-620" aria-label="Permalink to &quot;职场新人如何让别人感觉你工作能力很强？看完直接有3年工作经验 {#s-620}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **学校是跟团游，职场是自由行——没有人来安排你，主动获取信息才能避免成为信息孤岛</p><p>**2. **组织中大量关键信息不在正式通知里，而在闲聊茶水间，你需要通过small talk成为低压力交流的对象</p><p>**3. **面对老板不是面对老师：老师有义务教你，老板要的是结果；教你不是老板的本职，而是对你的额外投资</p><p>**4. **新人要提升三方面能力（难度递增）：执行能力→总结能力→表达能力，其中表达能力价值最高</p><h4 id="s-621" tabindex="-1">5. 汇报工作时先给结论再展开，让领导用最低成本获取最高回报 <a class="header-anchor" href="#s-621" aria-label="Permalink to &quot;5. 汇报工作时先给结论再展开，让领导用最低成本获取最高回报 {#s-621}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「好状态是干出来的，不是等出来的」</em></p><p><strong>行动指南</strong></p><p>进入新公司后主动做信息连接者，用small talk建立低压力的人际渠道；汇报时先说结论再说过程</p><h3 id="s-622" tabindex="-1">AI工作流保姆级教程｜小白友好 用好AI是普通人最大的杠杆 <a class="header-anchor" href="#s-622" aria-label="Permalink to &quot;AI工作流保姆级教程｜小白友好 用好AI是普通人最大的杠杆 {#s-622}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-623" tabindex="-1">1. 不要拿自己去跟AI比，而是用它来增强自己——以我为主，为我所用 <a class="header-anchor" href="#s-623" aria-label="Permalink to &quot;1. 不要拿自己去跟AI比，而是用它来增强自己——以我为主，为我所用 {#s-623}&quot;">​</a></h4><h4 id="s-624" tabindex="-1">2. AI最容易上手的起点：问自己&quot;我每周重复做什么烦人的事&quot;，找到自动化候选 <a class="header-anchor" href="#s-624" aria-label="Permalink to &quot;2. AI最容易上手的起点：问自己&quot;我每周重复做什么烦人的事&quot;，找到自动化候选 {#s-624}&quot;">​</a></h4><p>**3. **自动化→Skill→Agent是AI使用的进阶路线：先做重复任务自动化，再做套路稳定的Skill，最后做复杂流程的Agent</p><p>**4. **Skill就是你的私房APP，过去用APP是别人洗好的不能改，Skill是你自己定制的专属工具</p><p><strong>金句</strong></p><p><em>「不要拿自己去跟AI比，而要用它来增强你自己」</em></p><p><strong>行动指南</strong></p><p>花一周时间记录重复性任务，从最简单的自动化开始（如每日数据汇报、会议纪要整理），逐步搭建个性化AI工作流</p><h3 id="s-625" tabindex="-1">如何把清晰的脑子养回来？看完你将不可逆地变聪明 <a class="header-anchor" href="#s-625" aria-label="Permalink to &quot;如何把清晰的脑子养回来？看完你将不可逆地变聪明 {#s-625}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-626" tabindex="-1">1. 大脑不是在退化，而是被信息环境&quot;工伤&quot;了——信息丰富造成注意力匮乏 <a class="header-anchor" href="#s-626" aria-label="Permalink to &quot;1. 大脑不是在退化，而是被信息环境&quot;工伤&quot;了——信息丰富造成注意力匮乏 {#s-626}&quot;">​</a></h4><h4 id="s-627" tabindex="-1">2. 高手顺应大脑，普通人反大脑；大脑可塑性是双向的，行为能弄坏也能修好 <a class="header-anchor" href="#s-627" aria-label="Permalink to &quot;2. 高手顺应大脑，普通人反大脑；大脑可塑性是双向的，行为能弄坏也能修好 {#s-627}&quot;">​</a></h4><p>**3. **学习和囤积知识会成瘾，没有行动承接的知识变成大脑的负债，演变成反刍、纠结和幻想</p><h4 id="s-628" tabindex="-1">4. 高手的专注是资产不是燃料——每次都在积累可复用的知识卡片，而非一次性消耗 <a class="header-anchor" href="#s-628" aria-label="Permalink to &quot;4. 高手的专注是资产不是燃料——每次都在积累可复用的知识卡片，而非一次性消耗 {#s-628}&quot;">​</a></h4><h4 id="s-629" tabindex="-1">5. 真正稀缺的不是信息，而是信息跟你有什么关系、经验能否服务于当下的选择 <a class="header-anchor" href="#s-629" aria-label="Permalink to &quot;5. 真正稀缺的不是信息，而是信息跟你有什么关系、经验能否服务于当下的选择 {#s-629}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「没有行动承接的知识会变成大脑的负债」</em></p><p><strong>行动指南</strong></p><p>清空大脑缓存——学什么就立刻做最小行动（写300字、发1条内容）；建立外接大脑（白板/办公本），把脑内风暴变成可操作的外部对象</p><h3 id="s-630" tabindex="-1">越是低能量，越要过有秩序的生活，好状态就是好运气 <a class="header-anchor" href="#s-630" aria-label="Permalink to &quot;越是低能量，越要过有秩序的生活，好状态就是好运气 {#s-630}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **人低谷时最先放弃的是把自己收拾干净，居住空间开始失序，而这恰恰是最不该放弃的</p><h4 id="s-631" tabindex="-1">2. 上班后保持体面和好状态其实很难，但越是低能量越需要生活秩序来托住自己 <a class="header-anchor" href="#s-631" aria-label="Permalink to &quot;2. 上班后保持体面和好状态其实很难，但越是低能量越需要生活秩序来托住自己 {#s-631}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「好状态就是好运气」</em></p><p><strong>行动指南</strong></p><p>低能量时先从最基本的体面和秩序开始恢复——收拾好自己、整理好空间</p><h3 id="s-632" tabindex="-1">上班累，下班瘫，如何快速恢复能量？千万别把身体当耗材 <a class="header-anchor" href="#s-632" aria-label="Permalink to &quot;上班累，下班瘫，如何快速恢复能量？千万别把身体当耗材 {#s-632}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **职场通过工位、KPI、考勤把身体训练成有用且服从的工具，久而久之你自己成了自己的监工</p><p>**2. **把身体当耗材的逻辑：困了靠咖啡、憋尿憋情绪——能忍反被夸&quot;抗压强&quot;，不舒服要休息反被说&quot;太娇气&quot;</p><p>**3. **具身认知理论：姿势、呼吸、身体状态会反过来塑造你的心理——你应该学会用身体指挥大脑</p><h4 id="s-633" tabindex="-1">4. 关键第一步是健联：让脑子闭嘴，把感官交还给身体 <a class="header-anchor" href="#s-633" aria-label="Permalink to &quot;4. 关键第一步是健联：让脑子闭嘴，把感官交还给身体 {#s-633}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「很多时候世界是错的，身体才是对的」</em></p><p><strong>行动指南</strong></p><p>感觉糟糕时先洗个澡（人类重启键），用感官体验（气味、水温、食物的汁水）把注意力拉回身体当下</p><h3 id="s-634" tabindex="-1">为什么有些人看起来就工作能力很强？学会就能早点下班、摆脱瞎忙的职场微习惯 <a class="header-anchor" href="#s-634" aria-label="Permalink to &quot;为什么有些人看起来就工作能力很强？学会就能早点下班、摆脱瞎忙的职场微习惯 {#s-634}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **瞎忙三种表现：救火队员（时间被小事切碎）、难以专注（想了一周没启动）、返工白干（方向错标准没对齐）</p><p>**2. **好状态是干出来的不是等出来的——先拧开生锈的水龙头让水流一会儿，浑水才会变清</p><p>**3. **默认自己第一版就是做垃圾——快速倒出脑子里所有东西，动手本身就是思考，答案在落地时才出现</p><p>**4. **真正的自律背后都是他律，环境比意志力强100倍——与其问&quot;怎么更自律&quot;，不如问&quot;怎么让这事不需要自律&quot;</p><p><strong>金句</strong></p><p><em>「不要追求一次性到位，你要追求的是迭代频率」</em></p><p><strong>行动指南</strong></p><p>先写脏稿快速启动；公开承诺具体时间点来制造他律；主动设计&quot;不得不&quot;的环境（如组建学习小组互相督促）</p><h3 id="s-635" tabindex="-1">不上班怎么活？未来5年你不得不应对的职场新变化 <a class="header-anchor" href="#s-635" aria-label="Permalink to &quot;不上班怎么活？未来5年你不得不应对的职场新变化 {#s-635}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **小而美的时代正在到来：三叶草组织模型——未来公司分为核心员工、外包团队和零工，大部分人将变成独立作战个体</p><h4 id="s-636" tabindex="-1">2. 核心策略：先做小确保能活，再做强确保活得好 <a class="header-anchor" href="#s-636" aria-label="Permalink to &quot;2. 核心策略：先做小确保能活，再做强确保活得好 {#s-636}&quot;">​</a></h4><p>**3. **这个时代最大红利在草台班子的&quot;野工作&quot;上，每次时代变革都会抛出大量未被定义的职业机会</p><p>**4. **职业正从中心化（金字塔攀爬）走向去中心化（往四处走），接受这个现实才能打开更多可能性</p><p>**5. **野工作的选择标准：真正喜欢到不赚钱也觉得值，且试错成本足够低（不用裸辞all in）</p><p><strong>金句</strong></p><p><em>「先做小确保能活，再做强确保活得好」</em></p><p><strong>行动指南</strong></p><p>盘点自己的兴趣爱好及相关产业；用最小成本试错（不裸辞、不搭团队、不先投入大笔钱）；学会识别和利用杠杆（如AI工具）</p><h3 id="s-637" tabindex="-1">向上社交如何落落大方不怯场？如何让贵人主动帮你? <a class="header-anchor" href="#s-637" aria-label="Permalink to &quot;向上社交如何落落大方不怯场？如何让贵人主动帮你? {#s-637}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **换圈子的本质是换你在社会结构中的位置——换了圈子才能换认知，换了认知才能换资源</p><h4 id="s-638" tabindex="-1">2. 你自己就是你最常接触五个人的平均值 <a class="header-anchor" href="#s-638" aria-label="Permalink to &quot;2. 你自己就是你最常接触五个人的平均值 {#s-638}&quot;">​</a></h4><h4 id="s-639" tabindex="-1">3. 人和人之间的关系开诚布公的仰慕反而更舒适，不需要卑躬屈膝 <a class="header-anchor" href="#s-639" aria-label="Permalink to &quot;3. 人和人之间的关系开诚布公的仰慕反而更舒适，不需要卑躬屈膝 {#s-639}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「上层的空气更新鲜」</em></p><p><strong>行动指南</strong></p><p>主动去迭代自己的圈子，不因为身份低位而怯场，以坦诚和真诚的态度与比自己厉害的人交往</p><h3 id="s-640" tabindex="-1">太急是一种很强的负能量 一个人如果长期处于过度压力中会慢慢变笨 <a class="header-anchor" href="#s-640" aria-label="Permalink to &quot;太急是一种很强的负能量 一个人如果长期处于过度压力中会慢慢变笨 {#s-640}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **急分两种：主动的急（无法忍受悬而未决，用大量动作获得掌控感）和被动的急（被催促裹挟），本质都是持续生理应激</p><p>**2. **人类压力开关失灵——没有现实中狮子追，但想象中的狮子让皮质醇持续升高，睡眠差、易生病、情绪阈值低</p><p>**3. **不要背负别人的急迫感——急会从权力大方向小方传染，你要在别人催和你急之间装防火墙</p><h4 id="s-641" tabindex="-1">4. 秒回本质是讨好——害怕被觉得不靠谱而应激；越秒回对方越默认你可以秒回 <a class="header-anchor" href="#s-641" aria-label="Permalink to &quot;4. 秒回本质是讨好——害怕被觉得不靠谱而应激；越秒回对方越默认你可以秒回 {#s-641}&quot;">​</a></h4><p>**5. **做不完是正常的——不要用&quot;做完所有事&quot;定义一天成功，而是&quot;最重要的事做好了没&quot;</p><p><strong>金句</strong></p><p><em>「你越秒回，对方就越默认你可以秒回」</em></p><p><strong>行动指南</strong></p><p>被催时不秒回，给出更从容的时间点而非越快越好；默认不打断自己正在进行的事；建立下班关机仪式（散步、护肤、关通知），让神经系统真正关机</p><h3 id="s-642" tabindex="-1">哪些诀窍真能让普通人挣到钱？年轻收入高的人都有迹可循 <a class="header-anchor" href="#s-642" aria-label="Permalink to &quot;哪些诀窍真能让普通人挣到钱？年轻收入高的人都有迹可循 {#s-642}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **先把月薪干到城市中位数以上再谈理财和搞钱——职场上打不出好成绩，自由市场更残酷</p><h4 id="s-643" tabindex="-1">2. 打工是责任最小的选择，一人公司需要极强独立决策能力和对孤独的承受力 <a class="header-anchor" href="#s-643" aria-label="Permalink to &quot;2. 打工是责任最小的选择，一人公司需要极强独立决策能力和对孤独的承受力 {#s-643}&quot;">​</a></h4><h4 id="s-644" tabindex="-1">3. 不要诉求宏大叙事，正常人从一万到一万五、一万五到两万就已经很棒了 <a class="header-anchor" href="#s-644" aria-label="Permalink to &quot;3. 不要诉求宏大叙事，正常人从一万到一万五、一万五到两万就已经很棒了 {#s-644}&quot;">​</a></h4><h4 id="s-645" tabindex="-1">4. 造富神话让你脑子乱、心也乱——主业不本分，副业不坚持，任何事都没积累 <a class="header-anchor" href="#s-645" aria-label="Permalink to &quot;4. 造富神话让你脑子乱、心也乱——主业不本分，副业不坚持，任何事都没积累 {#s-645}&quot;">​</a></h4><h4 id="s-646" tabindex="-1">5. 在现状上开花——在本职事情上琢磨怎么多搞几千块，比幻想找到五连秘籍更健康 <a class="header-anchor" href="#s-646" aria-label="Permalink to &quot;5. 在现状上开花——在本职事情上琢磨怎么多搞几千块，比幻想找到五连秘籍更健康 {#s-646}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「多搞几千块，不要想得那么宏大，在现状上开花」</em></p><p><strong>行动指南</strong></p><p>在现有工作上找到增值点（如学新技能、承担新责任），把本职做到更好更值钱；不要被造富神话分散注意力</p><h3 id="s-647" tabindex="-1">越没钱越要对钱有概念，哪些诀窍真的能帮普通人搞到钱? <a class="header-anchor" href="#s-647" aria-label="Permalink to &quot;越没钱越要对钱有概念，哪些诀窍真的能帮普通人搞到钱? {#s-647}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-648" tabindex="-1">1. 小地方更吃家族资源，父母若普通人回老家只会更难——小地方人情社会更残酷 <a class="header-anchor" href="#s-648" aria-label="Permalink to &quot;1. 小地方更吃家族资源，父母若普通人回老家只会更难——小地方人情社会更残酷 {#s-648}&quot;">​</a></h4><p>**2. **你要开始&quot;卖自己&quot;——把知道的东西、能指导别人的东西，切成3-4个产品看有没有人买单</p><p>**3. **朋友圈是验证市场存活的第一阵地——连认识你的人都愿意付费，才有往大做的可能</p><h4 id="s-649" tabindex="-1">4. 先炸干主业的发展空间，提高可迁移技能和人脉，再在主业之外逐步拓展 <a class="header-anchor" href="#s-649" aria-label="Permalink to &quot;4. 先炸干主业的发展空间，提高可迁移技能和人脉，再在主业之外逐步拓展 {#s-649}&quot;">​</a></h4><p>**5. **买单才是最真实的验证——不是为了赚多少钱，而是验证独立于市场是否有人愿意买你的时间</p><p><strong>金句</strong></p><p><em>「买单才是最真实的验证」</em></p><p><strong>行动指南</strong></p><p>梳理自己在行业里积累的能力和人脉，做最小化测试（如99元30分钟咨询、请我喝杯咖啡随喜付费）；积累种子用户和秀Case后再设计更高客单价产品</p><h3 id="s-650" tabindex="-1">普通人不缺努力，缺的是一个赚钱系统 <a class="header-anchor" href="#s-650" aria-label="Permalink to &quot;普通人不缺努力，缺的是一个赚钱系统 {#s-650}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-651" tabindex="-1">1. 在职场中要刷存在感和价值感——不仅要被看见努力，更要被看见解决问题的能力 <a class="header-anchor" href="#s-651" aria-label="Permalink to &quot;1. 在职场中要刷存在感和价值感——不仅要被看见努力，更要被看见解决问题的能力 {#s-651}&quot;">​</a></h4><p>**2. **结果倒推法：从目标反推路径，自信到敢说&quot;前三个月不要工资&quot;，用能力换面试机会</p><p>**3. **在职场顺风顺水时看到天花板就要敢于跳出——晋升通道严苛+自己已经在职场外赚到更多钱=出去的信号</p><h4 id="s-652" tabindex="-1">4. 创业需要能力综合无大Bug、精神力极强，上班上不明白的不建议出来 <a class="header-anchor" href="#s-652" aria-label="Permalink to &quot;4. 创业需要能力综合无大Bug、精神力极强，上班上不明白的不建议出来 {#s-652}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「成功是成功之母」</em></p><p><strong>行动指南</strong></p><p>在职场中主动发现和解决问题创造价值（而非只做执行）；用结果倒推思维做职业规划——想达到什么目标就主动铺路</p><h3 id="s-653" tabindex="-1">上班最可怕的事是让我居然开始期待退休，期待衰老 <a class="header-anchor" href="#s-653" aria-label="Permalink to &quot;上班最可怕的事是让我居然开始期待退休，期待衰老 {#s-653}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **三段式人生（教育-就业-退休）是工业革命遗产，基于70岁寿命设计，但21世纪人很可能活到100岁</p><h4 id="s-654" tabindex="-1">2. 如果活到100岁，退休后需支撑30年生活积蓄——传统模式完全扛不住 <a class="header-anchor" href="#s-654" aria-label="Permalink to &quot;2. 如果活到100岁，退休后需支撑30年生活积蓄——传统模式完全扛不住 {#s-654}&quot;">​</a></h4><p>**3. **期待退休=期待衰老，这种心态本身就是被工作伦理规训的结果，需要跳出预设重新理解职业准备</p><p><strong>金句</strong></p><p><em>「上班最可怕的事是让我居然开始期待退休、期待衰老」</em></p><p><strong>行动指南</strong></p><p>重新规划职业生涯——不再以&quot;熬到退休&quot;为终点，而是构建可持续的多阶段人生，提前布局长寿时代的财务和技能储备</p><h3 id="s-655" tabindex="-1">冠军心态：人生没有失败，要么成长，要么成功 <a class="header-anchor" href="#s-655" aria-label="Permalink to &quot;冠军心态：人生没有失败，要么成长，要么成功 {#s-655}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **内耗的人想了一二三四五可能的问题，冠军直接先做——相信第一判断，答案在做事中获得</p><p>**2. **有野心不是贬义词，说明你对事情有追求；30岁更坦然面对自己的野心比20岁掩饰更自在</p><p>**3. **信心来自日积月累的真实努力，不是空心打气——你平时真的做出了努力，关键时刻才敢相信自己</p><p>**4. **专注做一件事本身就是很美好的体验，焦虑反而变成享受——因为感受到自己全身心专注</p><p><strong>金句</strong></p><p><em>「我更享受在赛场上的瞬间，焦虑都变成一种享受」</em></p><p><strong>行动指南</strong></p><p>日常小事练习果断（买东西不纠结就选第一判断）；想要什么直接说直接做；用&quot;想赢不怕输&quot;替代&quot;怕输才想赢&quot;</p><h3 id="s-656" tabindex="-1">我在杨幂身上看到了很值得学习的底气与自由 <a class="header-anchor" href="#s-656" aria-label="Permalink to &quot;我在杨幂身上看到了很值得学习的底气与自由 {#s-656}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-657" tabindex="-1">1. 母职与事业无法平衡只能取舍，自洽比平衡更重要——坦然接受你失去的那部分 <a class="header-anchor" href="#s-657" aria-label="Permalink to &quot;1. 母职与事业无法平衡只能取舍，自洽比平衡更重要——坦然接受你失去的那部分 {#s-657}&quot;">​</a></h4><p>**2. **主体性不是对身份的拒绝而是对身份的超越——你可以多角色切换，但不会被任何一个身份吞没</p><p>**3. **不被标签套住的关键：你不需要迎合&quot;好母亲&quot;或任何身份标签，当你自由完整活着，责任是自然衍生的选择</p><p>**4. **女性成为妈妈需要多维权支持系统：伴侣支持、经济独立、社会网络、职业灵活性，缺一不可</p><p><strong>金句</strong></p><p><em>「你当一个妈最好活得不像一个妈，你是夫妻最好让你是个女朋友」</em></p><p><strong>行动指南</strong></p><p>不做&quot;完美XX&quot;的标签囚徒，在角色中保留主体感；主动构建多维支持系统而非独自扛</p><h3 id="s-658" tabindex="-1">普通人如何培养财运，照着做你就在变富的路上 <a class="header-anchor" href="#s-658" aria-label="Permalink to &quot;普通人如何培养财运，照着做你就在变富的路上 {#s-658}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **资产不只是钞票——认知资产、健康资产、社交资产都可转化为金融资产，越花钱越有钱的关键是消费跟着长期人生主线走</p><p>**2. **认知资产：每个人都是知识工作者，面试就是老板评估你的业务认知然后支付匹配价格——转行时恶补行业调研、买专业书、付费咨询、请前辈吃饭来短期扩充认知</p><p>**3. **健康资产在25-35岁会经历大跳水，唯一能做的是让贬值慢一点——多做大频次的小动作，而非花大钱做大动作</p><p>**4. **社交资产是自愿交换和比较小的游戏——你数字太小时别人不愿跟你玩，情绪价值只有搭配实用价值才有用</p><p>**5. **一个人变强大不在于积累了多少金钱，而在于积累了多少真实影响力——你能被多少人利用，就能恰当利用多少人</p><p><strong>金句</strong></p><p><em>「人若无名，专心练剑」</em></p><p><strong>行动指南</strong></p><p>搭建高质量信息源（行业前辈、专业创作者）；健康投资选每天高频使用的小物品；社交先积累认知和实力，不用刻意攀缘</p><h3 id="s-659" tabindex="-1">高敏感的人不适合待在太底层的环境，一定要想办法托举自己向上走 <a class="header-anchor" href="#s-659" aria-label="Permalink to &quot;高敏感的人不适合待在太底层的环境，一定要想办法托举自己向上走 {#s-659}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **越是底层的地方人的动物性越强，高敏感人会被碾压；越发达的地方规则感更强，高敏感人感受到的是不被粗暴干涉的自由</p><p>**2. **高敏感人自我托举五建议：认知托举（让精神与更文明丰富的灵魂接轨）、物质托举（让好东西滋养你的气场）、位置选择（匹配敏感天赋的事业如创作者/咨询）、少干预别人因果、谨言慎行保持低调</p><p>**3. **敏感是天赋：同理心强能理解用户需求，大脑活跃能产出丰富创意，喜欢反思复盘有深度思考能力</p><p>**4. **物质不能定义人但能托举你——能力范围内用好东西增强气场，不是被消费主义洗脑而是赋能自己</p><p><strong>金句</strong></p><p><em>「极度敏感的人多半都很聪明，但精神内耗却很严重」</em></p><p><strong>行动指南</strong></p><p>选择与敏感天赋匹配的职业方向；在能力范围内用好物品给自己赋能；减少对负能量事件和他人因果的缠绕</p><h3 id="s-660" tabindex="-1">30岁才明白，要尽早明确人生主线，不要浪费自己的算力 <a class="header-anchor" href="#s-660" aria-label="Permalink to &quot;30岁才明白，要尽早明确人生主线，不要浪费自己的算力 {#s-660}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-661" tabindex="-1">1. 人与人最大区别不是执行力而是算力——太多虚假低效目标浪费了你的注意力内存 <a class="header-anchor" href="#s-661" aria-label="Permalink to &quot;1. 人与人最大区别不是执行力而是算力——太多虚假低效目标浪费了你的注意力内存 {#s-661}&quot;">​</a></h4><p>**2. **假目标三大表现：假性努力（低水平重复建设）、假装工作（为拍脑门KPI投入真实精力）、虚假宣传（被夸大产品包围）</p><p>**3. **攀缘毫无意义——维系人际关系最简单的方式是成为别人想要链接的人，有了专业技能后主动链接你的人自然变多</p><p>**4. **活得真三步：取舍（不让不重要的事占据算力）→求真（用第一性原理找本质，删非本质的）→守真（相信判断为自己下注，知行合一）</p><p><strong>金句</strong></p><p><em>「维系人际关系最简单的方式，就是你成为一个让别人想要链接的人」</em></p><p><strong>行动指南</strong></p><p>用第一性原理问自己&quot;决定我X的关键到底是什么&quot;，删掉非本质的；找到那一个解决了就能让其他问题变简单的核心问题</p><h3 id="s-662" tabindex="-1">ENFP挑战高效工作一天，最后是AI承担了所有 <a class="header-anchor" href="#s-662" aria-label="Permalink to &quot;ENFP挑战高效工作一天，最后是AI承担了所有 {#s-662}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-663" tabindex="-1">1. ENFP/创意型人格可以用AI作为外部执行器来弥补执行力短板 <a class="header-anchor" href="#s-663" aria-label="Permalink to &quot;1. ENFP/创意型人格可以用AI作为外部执行器来弥补执行力短板 {#s-663}&quot;">​</a></h4><h4 id="s-664" tabindex="-1">2. AI适合做调研、写长文档/分析PDF、延伸重要问题辅助决策、提供情绪价值 <a class="header-anchor" href="#s-664" aria-label="Permalink to &quot;2. AI适合做调研、写长文档/分析PDF、延伸重要问题辅助决策、提供情绪价值 {#s-664}&quot;">​</a></h4><h4 id="s-665" tabindex="-1">3. 拖延时可让AI帮推灵感、推荐书单、审阅方案、预判甲方可能质疑的点 <a class="header-anchor" href="#s-665" aria-label="Permalink to &quot;3. 拖延时可让AI帮推灵感、推荐书单、审阅方案、预判甲方可能质疑的点 {#s-665}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「犹豫不决问豆包」</em></p><p><strong>行动指南</strong></p><p>把拖延不想做的事派给AI（写脚本、做调研、审查文档），让AI成为你的执行外挂</p><h3 id="s-666" tabindex="-1">原来身体出现这些症状，不是你懒，是初老了 <a class="header-anchor" href="#s-666" aria-label="Permalink to &quot;原来身体出现这些症状，不是你懒，是初老了 {#s-666}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **25岁后进入高密度人生阶段（熬夜、赶工、内耗），身体和皮肤都在加速变化，这不是懒而是生理转折</p><p>**2. **干性肌肤年轻时皮肤好但老得快，油性肌肤年轻时长痘但压力不大时年龄增长反而变好</p><p>**3. **压力大时人会本能想吃高油高辣——因为那是你一天中少有的快乐，但这是恶性循环</p><p>**4. **一个人不撩挑子最后都能担起来，但每个妈妈都不容易——在极端压力下人只能&quot;赶鸭子上架&quot;尽力而为</p><p><strong>金句</strong></p><p><em>「一个人不撩挑子，最后都能担起来」</em></p><p><strong>行动指南</strong></p><p>了解自己肤质和身体特性，针对性护理而非盲目消费；压力大时不要完全剥夺高油高辣的快乐，但要有意识地减量替代</p><h3 id="s-667" tabindex="-1">做强者其实比做弱者更轻松 <a class="header-anchor" href="#s-667" aria-label="Permalink to &quot;做强者其实比做弱者更轻松 {#s-667}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **社会赋予女性弱者设定（美丽但虚弱、缺乏野心、需要被保护、见好就收），不符合就会被纠正</p><p>**2. **欲强更强的三种特质：主动充能（创造高能量磁场）、减少外部损耗（不接受弱者设定）、欲强则强（在更大挑战中激发更强自我）</p><p>**3. **即便环境区别对待你，如何回应这种对待是你能决定的——别人叫你&quot;美女&quot;，你递上来名片说&quot;叫我XX就好&quot;</p><p>**4. **人的快乐很多时候来源于外在形象和内在形象达成一致——照顾好自己的状态就是在给自己充能</p><p><strong>金句</strong></p><p><em>「当一个女性不被单一角色绑架，她能在关系中创造松弛感」</em></p><p><strong>行动指南</strong></p><p>主动做让自己充能的事（写日记、运动、护肤）；不接受别人给你的弱者设定，用行动回应而非内耗；面对区别对待时明确表态</p><h3 id="s-668" tabindex="-1">向全网200万名股东述职【姜Dora】一个百万粉博主的创业故事 <a class="header-anchor" href="#s-668" aria-label="Permalink to &quot;向全网200万名股东述职【姜Dora】一个百万粉博主的创业故事 {#s-668}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **大厂像罗马——生在罗马的人千辛万苦走到罗马的人各有各的苦，但到了发现高度精细化分工让你无法完整控制一件事</p><p>**2. **在别人的舞台上没有你的戏份，那就搭建自己的舞台——做自媒体不是因为想红而是因为在公司做不了内容</p><p>**3. **流量彩票砸向普通人很容易，但成为好博主要当创业来做——任何优缺点都会被无限放大</p><p>**4. **被抄袭是创作者最大的心魔，但对抗抄袭的最好方式不是纠缠而是跑得更快、做出别人抄不走的独特性</p><p>**5. **做好内容和商业化两件事：内容要有拳头产品，商业化要合理定价——定价即定位，便宜反而让人觉得不值</p><p><strong>金句</strong></p><p><em>「什么拯救过你，你就拿它来拯救这个世界」</em></p><p><strong>行动指南</strong></p><p>如果在当前平台无法完整发挥，就搭建自己的舞台；把被抄袭的内耗转化为跑更快的动力；定价不要自我贬低</p><h3 id="s-669" tabindex="-1">中国式亲情，我和我爸好像真的不熟。陪54岁北漂老爸工作的一天 <a class="header-anchor" href="#s-669" aria-label="Permalink to &quot;中国式亲情，我和我爸好像真的不熟。陪54岁北漂老爸工作的一天 {#s-669}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-670" tabindex="-1">1. 中国式亲情的特点：在一起没话说、分开没牵挂，表面是家人实际各活各的 <a class="header-anchor" href="#s-670" aria-label="Permalink to &quot;1. 中国式亲情的特点：在一起没话说、分开没牵挂，表面是家人实际各活各的 {#s-670}&quot;">​</a></h4><p>**2. **父辈对生活的热爱带有哲学性——&quot;人生是很美妙的事情，每件小事里都有无穷乐趣&quot;</p><p>**3. **代际冲突根源：父母希望你走安全路线（考公、回老家），你选择探索性人生，双方都不退让</p><p>**4. **经济独立是获得父母尊重的转折点——当你能给父母实质帮助，他们才开始把你当成年人</p><p><strong>金句</strong></p><p><em>「如果对漫长的人生感觉没底，那就先从小事做起」</em></p><p><strong>行动指南</strong></p><p>主动了解父母的生活（陪他们工作一天、聊聊日常）；用经济独立赢得关系中的对等地位</p><h3 id="s-671" tabindex="-1">不要温和地脱下那件长衫 <a class="header-anchor" href="#s-671" aria-label="Permalink to &quot;不要温和地脱下那件长衫 {#s-671}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **社会对年轻人精神撕裂：20岁前拼命让你穿长衫（知识改变命运），毕业后又嫌弃你不脱——这不是你的错</p><h4 id="s-672" tabindex="-1">2. 中国本科率仅约4%，长衫对很多人来说是唯一一件衣服，脱了就是秋之市场裸奔 <a class="header-anchor" href="#s-672" aria-label="Permalink to &quot;2. 中国本科率仅约4%，长衫对很多人来说是唯一一件衣服，脱了就是秋之市场裸奔 {#s-672}&quot;">​</a></h4><p>**3. **长衫的真正价值不是学历结果，而是穿长衫过程中获得的思维方式和做事习惯——这些永远不离开你</p><h4 id="s-673" tabindex="-1">4. 长衫只是你第一件衣服，绝不会是最后一件——你可以穿着长衫做任何事 <a class="header-anchor" href="#s-673" aria-label="Permalink to &quot;4. 长衫只是你第一件衣服，绝不会是最后一件——你可以穿着长衫做任何事 {#s-673}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「正是我们努力穿上长衫的过程，才让我们变成了更好的人」</em></p><p><strong>行动指南</strong></p><p>不轻视自己的学历和努力，穿着长衫去做任何工作都不丢人；把求学中获得的思维方式（翻译思维、资料搜集、独立行动）迁移到一切领域</p><h3 id="s-674" tabindex="-1">考研成功vs失败的二本生，6年后怎么样了？ <a class="header-anchor" href="#s-674" aria-label="Permalink to &quot;考研成功vs失败的二本生，6年后怎么样了？ {#s-674}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **考研动机往往超越功利——可能是安全感、独立意志、求之欲，但这些非功利动机恰恰支撑你走过最艰辛的阶段</p><p>**2. **成年人的第一课：独立做决定并为结果负责，可以失败痛哭但不要埋怨任何人——考研无论成败都是这个过程</p><p>**3. **不要轻易改志愿——第一直觉往往比反复权衡后改的正确率高，投入全部真心后无论什么结果都能接受</p><p>**4. **上岸组的共性：不犹豫、全情投入、短时间极高密度学习；落榜组的共性：动机不够纯粹、精力分散、中途改志愿</p><p>**5. **六年后上岸和落榜者都在各自的路上活得不错——考研不是人生分水岭，真正分水岭是你是否为自己做决定并负责</p><p><strong>金句</strong></p><p><em>「成年人的第一课就是独立做决定，并且为结果负责」</em></p><p><strong>行动指南</strong></p><p>考研前想清楚&quot;我是在为自己还是为别人做这个决定&quot;；选定后不犹豫全情投入；如果失败也不否定过程的价值</p><h3 id="s-675" tabindex="-1">20岁 vs 30岁开窍的6个变化 <a class="header-anchor" href="#s-675" aria-label="Permalink to &quot;20岁 vs 30岁开窍的6个变化 {#s-675}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **不在乎别人喜不喜欢我——喜欢你的人不会变，讨厌你的人也不会变，你不需要改变自己因为两拨人数大致不变</p><p>**2. **大方谈钱——金钱不是目的，是人在市场中价值创造能力的外显；找不到大目标时先想&quot;怎么挣更多钱&quot;，这会倒逼你思考价值创造</p><h4 id="s-676" tabindex="-1">3. 不害怕错过风口——一生做好一件事就够了，1米宽的坑挖到万米深 <a class="header-anchor" href="#s-676" aria-label="Permalink to &quot;3. 不害怕错过风口——一生做好一件事就够了，1米宽的坑挖到万米深 {#s-676}&quot;">​</a></h4><h4 id="s-677" tabindex="-1">4. 不在乎年龄焦虑——年龄给你带来的收获远比失去的多 <a class="header-anchor" href="#s-677" aria-label="Permalink to &quot;4. 不在乎年龄焦虑——年龄给你带来的收获远比失去的多 {#s-677}&quot;">​</a></h4><h4 id="s-678" tabindex="-1">5. 不再为关系疏远而难过——关系的质量比数量重要 <a class="header-anchor" href="#s-678" aria-label="Permalink to &quot;5. 不再为关系疏远而难过——关系的质量比数量重要 {#s-678}&quot;">​</a></h4><h4 id="s-679" tabindex="-1">6. 更懂得选择什么值得在乎——从求全到求真 <a class="header-anchor" href="#s-679" aria-label="Permalink to &quot;6. 更懂得选择什么值得在乎——从求全到求真 {#s-679}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「没有财务自由，就不要谈精神自由」</em></p><p><strong>行动指南</strong></p><p>不再为不喜欢你的人改变自己；用&quot;怎么多赚一点钱&quot;作为思考人生方向的朴实起点；找到一件事做到万米深</p><h3 id="s-680" tabindex="-1">十年情侣的居家日常，初恋变同事什么体验 <a class="header-anchor" href="#s-680" aria-label="Permalink to &quot;十年情侣的居家日常，初恋变同事什么体验 {#s-680}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **情侣做同事也会吵架（内容包装vs内容深度的分歧），但吵架让人更好了解彼此、磨合后更好在一起</p><h4 id="s-681" tabindex="-1">2. 判断一段关系的好坏标准：在一起后双方是否都变得更好 <a class="header-anchor" href="#s-681" aria-label="Permalink to &quot;2. 判断一段关系的好坏标准：在一起后双方是否都变得更好 {#s-681}&quot;">​</a></h4><p>**3. **咖啡馆的真正价值不是咖啡，而是30块钱就能获得一天优美环境的工位——北京的低价机房</p><p><strong>金句</strong></p><p><em>「因为吵架会让我们更好地了解彼此，有磨合我们才会更好地在一起」</em></p><p><strong>行动指南</strong></p><p>自由职业者可以利用咖啡馆作为低成本工作空间；关系中的冲突不必回避，关键是冲突后是否更深理解彼此</p><h3 id="s-682" tabindex="-1">27岁，大厂裸辞不上班的一年 <a class="header-anchor" href="#s-682" aria-label="Permalink to &quot;27岁，大厂裸辞不上班的一年 {#s-682}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **大部分人以为自己缺的是客观准备（钱和资源），真正卡住你的是主观准备（勇气）</p><p>**2. **自由市场比企业更残酷——企业其实在保护你的平庸和怠惰，脱离后你本人就是唯一且最重要的生产力</p><p>**3. **新世界玩法和旧世界不同——不能用大厂飞书OKR的那套管理自由生活，要放下旧规则</p><h4 id="s-683" tabindex="-1">4. 只做喜欢的事不管商务对接，结果连续两个月收入为零——创作和商务都必须面对 <a class="header-anchor" href="#s-683" aria-label="Permalink to &quot;4. 只做喜欢的事不管商务对接，结果连续两个月收入为零——创作和商务都必须面对 {#s-683}&quot;">​</a></h4><p>**5. **休息的第一周回家，睡眠突然变好——像干瘪的电池在贪婪充电，没有闹钟的生活才是真正的休息</p><p><strong>金句</strong></p><p><em>「企业其实在保护你的平庸和怠惰，当你脱离企业独自面对自由市场，你本人就是唯一且最重要的生产力」</em></p><p><strong>行动指南</strong></p><p>裸辞前确保有足够积蓄（至少2年）；脱身后放下旧世界的管理方式；不能只做喜欢的事，商务和创作都必须面对</p><h3 id="s-684" tabindex="-1">5分钟帮你摆脱社恐 ｜ 2种社恐类型你是哪种 <a class="header-anchor" href="#s-684" aria-label="Permalink to &quot;5分钟帮你摆脱社恐 ｜ 2种社恐类型你是哪种 {#s-684}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **社恐分两种：有社交意愿但缺社交能力 vs 有社交能力但缺社交意愿（不想社交是充电方式不同，不是缺陷）</p><p>**2. **内向者不必强迫自己社交——强迫只会让心情沮丧状态更差，改用HQC（High Quality Contact）策略</p><p>**3. **HQC方法：在有限的对接中每次都高质量完成——开始积极牵头、中间提醒节奏发现漏洞、结尾诚恳谢意和复盘</p><p>**4. **关系靠的是信任而非长袖善舞——一个害羞安静的人也可以有强大的获得他人信任的能力</p><p><strong>金句</strong></p><p><em>「获得别人的信任是一种非常神奇的能力」</em></p><p><strong>行动指南</strong></p><p>不必强迫自己变社牛，用HQC策略把每次有限对接都做到高质量；信任靠靠谱交付而非社交技巧</p>',299)])])}const u=s(o,[["render",p]]);export{g as __pageData,u as default};
